import { describe, expect, mock, test } from '@a0n/gnosis/test';

const { declaredDirectory } = await import('./runtime-self-context.ts');

const label = 'mocked-through-closure';
mock.module('./runtime-mock-dep.ts', () => ({
  readValue: () => label,
}));

const { readServiceValue } = await import('./runtime-mock-service.ts');

describe('Gnosis runtime compat', () => {
  test('avoids duplicate __dirname shims when source declares its own file context', () => {
    expect(declaredDirectory()).toBe('testing');
  });

  test('supports mock.module for transpiled local dependencies', () => {
    expect(readServiceValue()).toBe(label);
  });
});
